sp_widget.client_script:
api.controller = function($scope, $location) {
    /* widget controller */
	var c = this;
	c.shared = c.widget.options.shared;

	c.onCancel = function() {
		c.shared.cancelled=true;
		$scope.$parent.$parent.buttonClicked({ label: "Cancel", cancel: true });
	};

	c.onDiscardChanges = function() {
		c.shared.discardChanges=true;
		$scope.$parent.$parent.buttonClicked({ label: "OK", primary: true });
	};	

	c.onSubmit = function() {
		c.shared.saveDraft=true;
		$scope.$parent.$parent.buttonClicked({ label: "OK", primary: true });
	};
};

sp_widget.css:
/* No CSS here. Add via Tasker Theme */
.action-btn {
  margin-right: 5px;
}

