// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: Tasker Modal - Task Cancellation Comment
//------------------------------------------------------------------------------------------------------------------------
// 2.8 | 2022-06-16 | raj | STRY0119918 - New Task Form- Allow switching Form Views save the Task as Draft
//                          New Widget 
// 2.8 | 2022-06-28 | raj | STRY0124406 - Save as Draft in New Task Form- New modal when clicking another "Form View"
//											Updates in Server Script and HTML 
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options) {
	main();

	function main() {
		data.sys_id = (input || {}).sys_id || (options || {}).sys_id || $sp.getValue('sys_id');
		_buildMessages();
		_setDataDefaults();
	}

	function _buildMessages() {
		data.cancelButtonText = gs.getMessage('cancel');
		data.discardChangesButtonText = gs.getMessage('Tasker - Button - Discard Changes');
		data.submitButtonText = gs.getMessage('Tasker - Button - Save as Draft');
		data.submitButtonTexti = gs.getMessage('continue');

		data.msgBody2 = gs.getMessage('Warning');
		data.msgBody2i = gs.getMessage('Information Notice');

		data.msgBody3 = gs.getMessage('Tasker - Switching between forms will not save your input data changes.');
		data.msgBody3i = gs.getMessage('Tasker - You are about to switch the Form View. Fields will be hidden or displayed upon selection');

		data.msgBody4 = gs.getMessage('Tasker - Would you like to save this form as a draft before switching to another form?');
		data.msgBody4i = gs.getMessage('Tasker - Fields no longer displayed will be available in the Advanced Form View. The Tasker Type will be updated based on you selection');

		data.msgBody5i = gs.getMessage('Tasker - Are you sure you would like to continue?');
	}
	// copy to data from input or options
	function _optCopy(names) {
		names.forEach(function(name) {
			data[name] = input[name] || options[name];
		});
	}

	function _setDataDefaults() {
		data.submit = false;
	}
})($sp, input, data, options);
